class Observable {
  constructor() {
    this.subscribers = new Map();
  }

  subscribe(event, callback) {
    if (!this.subscribers.has(event)) this.subscribers.set(event, new Set());
    this.subscribers.get(event).add(callback);
    return () => this.subscribers.get(event).delete(callback);
  }

  emit(event, data) {
    if (this.subscribers.has(event)) {
      this.subscribers.get(event).forEach(cb => cb(data));
    }
  }
}

Array.prototype.myReduce = function(callback, initialValue) {
  let accumulator = initialValue;
  let startIndex = 0;
  if (accumulator === undefined) {
    accumulator = this[0];
    startIndex = 1;
  }
  for (let i = startIndex; i < this.length; i++) {
    accumulator = callback(accumulator, this[i], i, this);
  }
  return accumulator;
};

function createLazyLoader(importFn) {
  let module = null;
  let loading = null;

  return async function(...args) {
    if (!module) {
      if (!loading) loading = importFn();
      module = await loading;
    }
    return module.default ? module.default(...args) : module;
  };
}
// Usage: const lazyMath = createLazyLoader(() => import('./math.js'));

async function retry(fn, maxRetries = 3, baseDelay = 1000) {
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await fn();
    } catch (error) {
      if (attempt === maxRetries) throw error;
      const delay = baseDelay * Math.pow(2, attempt);
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }
}

function createStateMachine(config) {
  let currentState = config.initial;

  return {
    get state() { return currentState; },
    transition(event) {
      const stateConfig = config.states[currentState];
      const nextState = stateConfig?.on?.[event];
      if (!nextState) throw new Error(`Invalid transition: ${currentState} -> ${event}`);
      currentState = nextState;
      return currentState;
    }
  };
}
// Usage: createStateMachine({ initial: 'idle', states: { idle: { on: { START: 'running' } }, running: { on: { STOP: 'idle' } } } })

class PubSub {
  constructor() {
    this.subs = new Map();
  }

  subscribe(pattern, fn) {
    if (!this.subs.has(pattern)) this.subs.set(pattern, new Set());
    this.subs.get(pattern).add(fn);
    return () => this.subs.get(pattern).delete(fn);
  }

  publish(topic, data) {
    this.subs.forEach((fns, pattern) => {
      const regex = new RegExp('^' + pattern.replace(/\*/g, '.*') + '$');
      if (regex.test(topic)) fns.forEach(fn => fn(data));
    });
  }
}
